SELECT COUNT(1)
FROM upload_parts
WHERE upload_session_id = #{uploadSessionId}

SELECT COALESCE(SUM(part_size), 0)
FROM upload_parts
WHERE upload_session_id = #{uploadSessionId}

SELECT id, upload_session_id, part_number, part_size, etag, checksum, status, uploaded_at
FROM upload_parts
WHERE upload_session_id = #{uploadSessionId}
  AND part_number = #{partNumber}
LIMIT 1
